<?php
/**
 * Type Badge dynamic block render entrypoint.
 *
 * Delegates to the renderer in render-functions.php so the same function
 * services the block-registration render path. Generated by
 * `pnpm dailyos:new-block --template primitive-inline type-badge`.
 *
 * @package DailyOS
 *
 * @var array<string, mixed> $attributes Block attributes from core.
 */

declare(strict_types=1);

if ( ! defined( 'ABSPATH' ) ) {
	return '';
}

if ( ! function_exists( 'dailyos_type_badge_render' ) ) {
	require_once __DIR__ . '/render-functions.php';
}

$attributes = isset( $attributes ) && is_array( $attributes ) ? $attributes : [];
return dailyos_type_badge_render( $attributes );
